func solve(landStartTime: Array<Int64>, landDuration: Array<Int64>, waterStartTime: Array<Int64>, waterDuration: Array<Int64>): Int64 {
    var best: Int64 = 1_000_000_000

    for i in 0 until landStartTime.size() {
        for j in 0 until waterStartTime.size() {
            val landEnd = landStartTime[i] + landDuration[i]
            val waterEnd = waterStartTime[j] + waterDuration[j]

            val option1 = max(landEnd, waterStartTime[j]) + waterDuration[j]
